"use client";

import React, { useEffect, useState } from "react";
import Link from "next/link";
import styles from "./HeroSection.module.scss";

export default function HeroSection() {
  const [mounted, setMounted] = useState(false);
  const [activeMood, setActiveMood] = useState(0);

  const moods = ["😌 Calm", "😊 Happy", "😟 Anxious", "🎯 Focused"];
  const moodColors = [
    { bg: "#e8f4ed", color: "#2d7a4a" },
    { bg: "#fef3e2", color: "#a05c10" },
    { bg: "#fce8e8", color: "#a02020" },
    { bg: "#e8ecf8", color: "#2040a0" },
  ];
  const bars = [55, 35, 70, 80, 45, 90, 75];

  useEffect(() => {
    setMounted(true);
    const interval = setInterval(() => {
      setActiveMood((prev) => (prev + 1) % moods.length);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  return (
    <section className={styles.hero}>
      <div className={`${styles.blob} ${styles.blob1}`} aria-hidden="true" />
      <div className={`${styles.blob} ${styles.blob2}`} aria-hidden="true" />
      <div className={`${styles.blob} ${styles.blob3}`} aria-hidden="true" />

      {/* ── LEFT ── */}
      <div className={`${styles.left} ${mounted ? styles.leftVisible : ""}`}>

        <span className={styles.badge}>
          <span className={styles.badgeDot} />
          Sentira Wellness · New
        </span>

        <h1 className={styles.title}>
          Feel Better,{" "}
          <em className={styles.titleAccent}>Every Single Day.</em>
        </h1>

        <p className={styles.sub}>
          Track your emotions, reduce stress, and build lasting mental habits
          with personalised daily check-ins and guided exercises.
        </p>

        <div className={styles.ctas}>
          <Link href="/register" className={styles.btnMain}>
            Get Started Free
            <svg width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
              <path d="M2.5 7h9M8 3.5 11.5 7 8 10.5" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </Link>
          <Link href="#features" className={styles.btnSec}>
            See how it works
          </Link>
        </div>

        <div className={styles.proof}>
          <div className={styles.avatars}>
            {["S","M","A","+"].map((l, i) => (
              <div key={i} className={`${styles.av} ${styles[`av${i+1}`]}`}>{l}</div>
            ))}
          </div>
          <span className={styles.proofText}>
            <strong>50,000+</strong> people improving their mental health
          </span>
        </div>

        <div className={styles.statRow}>
          {[
            { value: "4.9★", label: "App Store rating" },
            { value: "92%",  label: "Feel less stressed" },
            { value: "2 min",label: "Daily check-in" },
          ].map(({ value, label }) => (
            <div key={label} className={styles.statPill}>
              <span className={styles.statValue}>{value}</span>
              <span className={styles.statLabel}>{label}</span>
            </div>
          ))}
        </div>
      </div>

      {/* ── RIGHT — phone mockup ── */}
      <div className={`${styles.right} ${mounted ? styles.rightVisible : ""}`}>

        {/* Floating card — streak */}
        <div className={`${styles.floatCard} ${styles.floatLeft}`}>
          <div className={styles.floatIcon} style={{ background:"linear-gradient(135deg,#e8f4ed,#c8e8d4)" }}>
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
              <path d="M8 2C8 2 3 5.5 3 9a5 5 0 0010 0C13 5.5 8 2 8 2Z" fill="#2d7a4a" opacity=".5"/>
              <path d="M8 5.5V10M5.5 8H10" stroke="#2d7a4a" strokeWidth="1.4" strokeLinecap="round"/>
            </svg>
          </div>
          <div>
            <div className={styles.floatLabel}>7-day streak!</div>
            <div className={styles.floatSub}>Keep it up</div>
          </div>
        </div>

        {/* Floating card — stat */}
        <div className={`${styles.floatCard} ${styles.floatRight}`}>
          <div className={styles.floatBig}>92%</div>
          <div className={styles.floatSub}>feel less stressed</div>
        </div>

        {/* Phone */}
        <div className={styles.phoneWrap}>
          <div className={styles.phone}>
            <div className={styles.phoneScreen}>

              <div className={styles.statusBar}>
                <span>9:41</span>
                <svg width="11" height="8" viewBox="0 0 11 8" fill="none">
                  <rect x="0" y="3" width="2" height="5" rx="0.5" fill="#1a1208"/>
                  <rect x="3" y="2" width="2" height="6" rx="0.5" fill="#1a1208"/>
                  <rect x="6" y="0.5" width="2" height="7.5" rx="0.5" fill="#1a1208"/>
                  <rect x="9" y="0" width="2" height="8" rx="0.5" fill="#1a1208" opacity=".25"/>
                </svg>
              </div>

              <div className={styles.greeting}>
                Good morning,{" "}
                <span className={styles.greetingName}>Sarah 🌿</span>
                <div className={styles.greetingSub}>How are you feeling today?</div>
              </div>

              <div className={styles.moodCard}>
                <div className={styles.cardLabel}>Today&apos;s mood</div>
                <div className={styles.moodRow}>
                  {moods.map((m, i) => (
                    <button
                      key={m}
                      onClick={() => setActiveMood(i)}
                      className={styles.moodPill}
                      style={{
                        background: activeMood === i ? moodColors[i].bg : "rgba(255,255,255,0.5)",
                        color:      activeMood === i ? moodColors[i].color : "#8a7055",
                        transform:  activeMood === i ? "scale(1.08)" : "scale(1)",
                        fontWeight: activeMood === i ? 700 : 500,
                        border:     activeMood === i
                          ? `1.5px solid ${moodColors[i].color}30`
                          : "1.5px solid transparent",
                      }}
                    >
                      {m}
                    </button>
                  ))}
                </div>
              </div>

              <div className={styles.streakCard}>
                <div className={styles.streakIcon}>
                  <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                    <path d="M8 1C8 1 4 5 4 9a4 4 0 008 0C12 5 8 1 8 1Z" fill="#c4895a"/>
                    <path d="M8 6v4M6.5 8.5h3" stroke="#fff" strokeWidth="1.2" strokeLinecap="round"/>
                  </svg>
                </div>
                <div>
                  <div className={styles.streakNum}>7 days</div>
                  <div className={styles.streakSub}>Current wellness streak</div>
                </div>
              </div>

              <div className={styles.chartCard}>
                <div className={styles.cardLabel}>Weekly mood score</div>
                <div className={styles.chartBars}>
                  {bars.map((h, i) => (
                    <div
                      key={i}
                      className={`${styles.bar} ${h >= 60 ? styles.barLit : ""}`}
                      style={{ height:`${h}%` }}
                    />
                  ))}
                </div>
              </div>

              <div className={styles.notif}>
                <div className={styles.notifIcon}>
                  <svg width="12" height="12" viewBox="0 0 14 14" fill="none">
                    <circle cx="7" cy="7" r="5.5" stroke="#fff" strokeWidth="1.2"/>
                    <path d="M7 4.5V7.5L9 9" stroke="#fff" strokeWidth="1.2" strokeLinecap="round"/>
                  </svg>
                </div>
                <div className={styles.notifText}>
                  <strong>Time for your check-in</strong><br/>
                  2 min · Breathing exercise ready
                </div>
              </div>

            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
